def call_agent(chunks,model_name,api_key,ollama_flag):
    SYSTEM_PROMPT = """
                        You are an expert software architect and code intelligence system.

                        Your task is to generate a FILE-LEVEL summary from multiple chunk/function summaries belonging to source files.

                        INPUT FORMAT:
                        You will receive one or more groups of chunk summaries.

                        Each group represents EXACTLY ONE source file.

                        A request MAY contain multiple files, but:
                        - chunk summaries from different files are already grouped separately
                        - you must process each file independently
                        - NEVER merge understanding across different files

                        You may also receive:
                        1. File metadata
                        2. Chunk summaries extracted from the file
                        3. Optional dependency graph information
                        4. Optional call graph information

                        YOUR OBJECTIVES:
                        - Understand the overall purpose of each file
                        - Merge related function/class behavior into a coherent architectural summary
                        - Identify the primary responsibility of the file
                        - Detect internal symbol interactions
                        - Infer execution flow and data flow
                        - Reduce redundancy across chunk summaries
                        - Preserve important implementation semantics
                        - Produce retrieval-friendly architectural summaries

                        IMPORTANT PROCESSING RULES:

                        - Treat each file group independently
                        - Never combine semantics between separate files
                        - Do NOT simply concatenate chunk summaries
                        - Build a higher-level architectural understanding
                        - Infer the architectural role of the file

                        Possible architectural roles include:
                        - controller
                        - service
                        - middleware
                        - utility
                        - hook
                        - repository
                        - schema
                        - worker
                        - config
                        - component
                        - adapter
                        - orchestrator
                        - validator
                        - client
                        - provider

                        CONTEXT WINDOW RULES:

                        - Every file group is guaranteed to fit within the model context window
                        - If a file is too large, it will be excluded from the request entirely
                        - Therefore, assume all provided chunk summaries for a file are complete
                        - Never assume missing chunks unless explicitly stated

                        SEMANTIC UNDERSTANDING RULES:

                        - Explain how functions/classes collaborate internally
                        - Identify important workflows inside the file
                        - Mention architecturally significant imports/dependencies only
                        - Public API should contain externally useful exports only
                        - Avoid repeating trivial helper logic
                        - Compress repetitive behavior into concise summaries
                        - Preserve important:
                        - security logic
                        - performance behavior
                        - caching
                        - concurrency
                        - validation
                        - retry/fallback handling
                        - error handling
                        when architecturally relevant

                        DOMAIN-SPECIFIC UNDERSTANDING:

                        If the file contains:
                        - React/UI logic:
                        explain rendering flow, state management, hooks, event flow, and component responsibilities

                        - Backend/service logic:
                        explain request lifecycle, business logic, validation, orchestration, and persistence flow

                        - Infrastructure/config logic:
                        explain initialization behavior, environment configuration, dependency wiring, or runtime setup

                        - Data/model logic:
                        explain schema structure, transformation rules, validation, and storage concerns

                        SYMBOL ID RULES:

                        - Use exact symbol identifiers when available
                        - Never invent fake paths
                        - Keep identifiers deterministic and stable
                        - Preserve provided filepath information exactly

                        OUTPUT REQUIREMENTS:

                        - Return ONLY structured output
                        - Do not include markdown
                        - Do not explain reasoning
                        - Keep summaries dense, technical, semantic, and retrieval-friendly
                        - Avoid conversational language
                        - Prefer architectural understanding over low-level implementation detail
                    """
    try:
        if ollama_flag == True:
            llm = load_model_ollama(model_name)
        else:
            llm = load_model_byok(model_name,api_key)
        structured_llm = llm.with_structured_output(FileLevelSummaryList)
        messages = [
            (
                "system",
                SYSTEM_PROMPT,
            ),
            ("human", f"Analyze the given chunks and generate the answer according to the system prompt only {chunks}"),
        ]
        print(f"Successfully imported and structured the model = {model_name} for file summary")
        ai_msg = structured_llm.invoke(messages)
        return ai_msg

    except Exception as e:
        print(f"Agent for source code analysis failed!! as  {e}")

def generate_file_summary(chunks_with_summary,model_name,api_key,ollama_flag):
    MAX_TOKEN_LIMIT =  load_max_token(model_name,ollama_flag)
    group_by_filename = defaultdict(list)
    for chunk in (chunks_with_summary):
        filepath = chunk.function_info.filepath
        group_by_filename[filepath].append(chunk)

    current_request_chunks_size = 0
    give_chunks = []
    ai_msg = []
    try :
        tokenizer = load_tokenizer(model_name)
        for filepath,file_chunks in (group_by_filename.items()):
            str_file_chunks = "".join(map(str,file_chunks))
            current_request_chunks_size += len(tokenizer.encode(str_file_chunks))
            if current_request_chunks_size >= MAX_TOKEN_LIMIT:
                result = call_agent(give_chunks,model_name,api_key,ollama_flag)
                ai_msg.extend(result.summaries)
                if ollama_flag == False:
                    print("Waiting 60 seconds....")
                    time.sleep(60)
                    print("Done waiting 60 seconds!!")
                else:
                    print("Waiting 10 seconds....")
                    time.sleep(10)
                    print("Done waiting 10 seconds!!")
                current_request_chunks_size = len(tokenizer.encode(file_chunks))
                give_chunks = []
            give_chunks.append(file_chunks)

        if give_chunks:
            result = call_agent(give_chunks,model_name,api_key,ollama_flag)
            ai_msg.extend(result.summaries)
        return ai_msg
    except Exception as e:
        print(f"Something went wrong while initiating code analysis via LLM as {e}")


